import { formatDevBuildBannerLines, getDevBuildSummary, isDevBuildActive, } from "../buildInfo.js";
import { hasCredentials } from "../config.js";
import { checkForSdkUpdatesOffline, formatSdkUpdateLine, } from "../sdkUpdates.js";
import { checkForUpdate, detectLegacyInstall, legacyMigrationMessage, } from "../updates.js";
export async function runSessionStart(currentVersion, platform, pluginRoot, scriptUrl) {
    const messages = [];
    const devBuildActive = isDevBuildActive(platform, scriptUrl);
    const prefix = devBuildActive ? "[Bitfab Dev]" : "[Bitfab]";
    if (devBuildActive && pluginRoot) {
        try {
            const summary = getDevBuildSummary(pluginRoot);
            if (summary) {
                messages.push(formatDevBuildBannerLines(summary, "Bitfab").join("\n"));
            }
        }
        catch { }
    }
    try {
        if (detectLegacyInstall(platform)) {
            messages.push(legacyMigrationMessage(platform, prefix));
        }
    }
    catch { }
    try {
        if (!hasCredentials()) {
            messages.push(`${prefix} Not authenticated. Run ${platform.setupHint} to connect your account and instrument your codebase.`);
        }
    }
    catch { }
    if (platform.supportsAutoUpdate) {
        try {
            const { current, latest, updateAvailable, autoUpdateEnabled } = await checkForUpdate(currentVersion, platform);
            if (updateAvailable && latest) {
                const lines = [`${prefix} Update available: v${current} → v${latest}.`];
                if (autoUpdateEnabled) {
                    lines.push(`          Auto-update is enabled — restart to apply.`);
                }
                else {
                    lines.push(`          Run ${platform.updateHint} to update, or enable auto-update: /plugin → Marketplaces → ${platform.marketplaceName} → Enable auto-update`);
                }
                messages.push(lines.join("\n"));
            }
        }
        catch { }
    }
    try {
        const outdated = checkForSdkUpdatesOffline(process.cwd()).filter((s) => s.updateAvailable && s.latest);
        if (outdated.length > 0) {
            const lines = [
                `${prefix} SDK update${outdated.length > 1 ? "s" : ""} available:`,
            ];
            for (const status of outdated) {
                lines.push(`          ${formatSdkUpdateLine(status)}`);
            }
            lines.push(`          Run ${platform.updateHint} to update.`);
            messages.push(lines.join("\n"));
        }
    }
    catch { }
    if (messages.length > 0) {
        process.stdout.write(JSON.stringify({ systemMessage: `\n${messages.join("\n")}` }));
    }
}
